+/// One layer of a DIT butterfly network where all blocks share the same single twiddle factor.
+///
+/// This is used for layer=0 of `first_half_general` (coset DFT). At layer=0, `half_block_size=1`
+/// so each block has exactly one row-pair, and all blocks clone the twiddle iterator from index 0,
+/// meaning every block uses `twiddle[0]` — the same value. By pre-broadcasting this once into a
+/// packed field, we eliminate `h/2 - 1` redundant `vpbroadcastd` instructions that would
+/// otherwise occur inside `DitButterfly::apply_to_rows` on each of the `h/2` blocks.
+fn dit_layer_uniform_twiddle<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    twiddle: F,
+    backwards: bool,
+) {
+    // layer=0 means half_block_size=1, block_size=2.
+    let width = submat.width();
+    debug_assert!(submat.height() >= 2);
+
+    // Pre-broadcast the twiddle once for all blocks.
+    let twiddle_packed = F::Packing::from(twiddle);
+
+    let process_block = move |block: &mut [F]| {
+        let (lo, hi) = block.split_at_mut(width);
+        // Apply butterfly inline using the pre-broadcast twiddle.
+        let (lo_packed, lo_suffix) = F::Packing::pack_slice_with_suffix_mut(lo);
+        let (hi_packed, hi_suffix) = F::Packing::pack_slice_with_suffix_mut(hi);
+        for (x_1, x_2) in lo_packed.iter_mut().zip(hi_packed.iter_mut()) {
+            let x_2_twiddle = *x_2 * twiddle_packed;
+            let new_x1 = *x_1 + x_2_twiddle;
+            *x_2 = *x_1 - x_2_twiddle;
+            *x_1 = new_x1;
+        }
+        for (x_1, x_2) in lo_suffix.iter_mut().zip(hi_suffix.iter_mut()) {
+            let x_2_twiddle = *x_2 * twiddle;
+            let new_x1 = *x_1 + x_2_twiddle;
+            *x_2 = *x_1 - x_2_twiddle;
+            *x_1 = new_x1;
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(2 * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
